# Category: format_string

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

void logError(const char* error_msg, const char* file_name, int line_number) {
    FILE* logfile = fopen("error.log", "a");
    if (logfile == NULL) {
        return;
    }

    // Write the error message to the log file
    fprintf(logfile, "%s: %d: %s\n", file_name, line_number, error_msg);

    // Close the log file
    fclose(logfile);
}